#!/usr/bin/env python3
"""
install_v3.py — Deploy FeatherV2 Application to Raspberry Pi
ExpeDRY Test System

Usage:
    python3 install_v3.py                    # install to /home/allied2/FeatherV2 (default)
    python3 install_v3.py /custom/path       # install to custom directory

This script extracts all Python and Kivy files from base64 encoding
and writes them to the filesystem.

Assets (PNG files) must be copied manually to the assets/ subdirectory.
"""

import base64
import os
import sys
from pathlib import Path

# ─────────────────────────────────────────────────────────────────────
# EMBEDDED FILE DICTIONARY — {relative_path: base64_encoded_content}
# ─────────────────────────────────────────────────────────────────────

FILES = {
    "camera/ColormapEnum.py": "",
    "camera/__init__.py": "ZnJvbSBjYW1lcmEgaW1wb3J0IHRoZXJtYWxjYW1lcmFDb250cm9sbGVyCmZyb20gY2FtZXJhIGltcG9ydCBndWlDb250cm9sbGVyCmZyb20gY2FtZXJhIGltcG9ydCBDb2xvcm1hcEVudW0KZnJvbSBjYW1lcmEgaW1wb3J0IHZhbHVlcwo=",
    "camera/guiController.py": "",
    "camera/thermalcameraController.py": "",
    "camera/values.py": "",
    "components/Controls.kv": "",
    "components/Controls.py": "",
    "components/SaveDialog.kv": "",
    "components/SaveDialog.py": "",
    "components/Test_Settings.kv": "",
    "components/Test_Settings.py": "",
    "components/WarningDialog.kv": "",
    "components/WarningDialog.py": "",
    "components/WeighDialog.kv": "",
    "components/WeighDialog.py": "",
    "components/WifiDialog.kv": "",
    "components/WifiDialog.py": "",
    "components/__init__.py": "",
    "main.py": "",
    "tester.kv": "",
    "utils/RS485.py": "",
    "utils/Relay.py": "",
    "utils/Scale.py": "",
    "utils/__init__.py": "ZnJvbSB1dGlscyBpbXBvcnQgdGhlbWUKZnJvbSB1dGlscyBpbXBvcnQgUmVsYXkKZnJvbSB1dGlscyBpbXBvcnQgUlM0ODUKZnJvbSB1dGlscyBpbXBvcnQgU2NhbGUK",
    "utils/theme.py": "",
}

# ─────────────────────────────────────────────────────────────────────
# INSTALLATION FUNCTION
# ─────────────────────────────────────────────────────────────────────

def install_files(install_dir):
    """
    Decode all embedded files and write them to the filesystem.

    Args:
        install_dir (str): Target installation directory

    Returns:
        bool: True if successful, False otherwise
    """
    install_path = Path(install_dir)

    try:
        # Create base directories
        print(f"[*] Installing to {install_dir}")
        install_path.mkdir(parents=True, exist_ok=True)
        (install_path / "utils").mkdir(exist_ok=True)
        (install_path / "components").mkdir(exist_ok=True)
        (install_path / "camera").mkdir(exist_ok=True)
        (install_path / "assets").mkdir(exist_ok=True)

        # Decode and write each file
        total = len(FILES)
        written = 0

        for rel_path, b64_content in sorted(FILES.items()):
            try:
                # Decode base64 content
                decoded = base64.b64decode(b64_content)

                # Write to filesystem
                file_path = install_path / rel_path
                file_path.parent.mkdir(parents=True, exist_ok=True)
                file_path.write_bytes(decoded)

                written += 1
                status = "OK"
                print(f"  [{written:2d}/{total}] {rel_path:<50} {status}")

            except Exception as e:
                print(f"  [!!] {rel_path:<50} ERROR: {e}")
                return False

        print(f"\n[+] Successfully wrote {written}/{total} files")

        # Asset note
        print("\n[!] Assets (PNG files) — Manual copy required:")
        print(f"    Copy ExpeDRY_logo.png and save-24.png to:")
        print(f"    {install_dir}/assets/")

        return True

    except Exception as e:
        print(f"[-] Installation failed: {e}")
        return False


def main():
    """Main entry point."""
    # Parse CLI arguments
    install_dir = "/home/allied2/FeatherV2"
    if len(sys.argv) > 1:
        install_dir = sys.argv[1]

    print("=" * 70)
    print("FeatherV2 Application Installer (v3)")
    print("=" * 70)
    print()

    success = install_files(install_dir)

    print()
    if success:
        print("[+] Installation complete!")
        sys.exit(0)
    else:
        print("[-] Installation failed!")
        sys.exit(1)


if __name__ == "__main__":
    main()
